  1→//! Project root detection for language frontends.
  2→//!
  3→//! Walks up from a target file looking for project marker files (package.json,
  4→//! tsconfig.json, go.mod, Cargo.toml). The detected root is passed to frontends
  5→//! so they can load project configuration (tsconfig, go.sum, etc.).
  6→
  7→use std::path::{Path, PathBuf};
  8→
  9→/// Marker files checked in priority order during project root detection.
 10→const MARKERS: &[(&str, ProjectKind)] = &[
 11→    ("package.json", ProjectKind::TypeScript),
 12→    ("tsconfig.json", ProjectKind::TypeScript),
 13→    ("go.mod", ProjectKind::Go),
 14→    ("Cargo.toml", ProjectKind::Rust),
 15→];
 16→
 17→/// The kind of project detected, derived from which marker file was found.
 18→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 19→pub enum ProjectKind {
 20→    TypeScript,
 21→    Go,
 22→    Rust,
 23→}
 24→
 25→/// A detected project root directory with its kind.
 26→#[derive(Debug, Clone, PartialEq, Eq)]
 27→pub struct ProjectRoot {
 28→    pub path: PathBuf,
 29→    pub kind: ProjectKind,
 30→}
 31→
 32→/// Walk up from `file_path` looking for project marker files.
 33→///
 34→/// Returns the first directory containing a marker, or `None` for isolated
 35→/// files with no project structure. The search starts from the file's parent
 36→/// directory and stops at the filesystem root.
 37→pub fn detect_project_root(file_path: &Path) -> Option<ProjectRoot> {
 38→    let start_dir = if file_path.is_dir() {
 39→        file_path.to_path_buf()
 40→    } else {
 41→        file_path.parent()?.to_path_buf()
 42→    };
 43→
 44→    let mut dir = start_dir;
 45→    loop {
 46→        for &(marker, kind) in MARKERS {
 47→            if dir.join(marker).exists() {
 48→                return Some(ProjectRoot {
 49→                    path: dir.clone(),
 50→                    kind,
 51→                });
 52→            }
 53→        }
 54→        match dir.parent() {
 55→            Some(parent) if parent != dir => dir = parent.to_path_buf(),
 56→            _ => return None,
 57→        }
 58→    }
 59→}
 60→
